import React from "react";
import AddTodoModal from "./AddTodoModal";
import { ToastContainer, toast } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";
import moment from "moment/moment"
import { deleteTodo } from "../../services/api";
const Todo = ({todo, setRefreshList}) => {
    const handleDelete = async () =>{
        try {
            const result = await deleteTodo(todo._id);
            if(result.success){
                toast.success("Todo Deleted")
                setRefreshList(new Date())
            }else{
                    toast.error(result.error || "Failed To Delete");
                }
        } catch (error) {
            console.error("Delete Error:", error);
            toast.error("Failed to delete todo. Please try again.");
        }
    }
    return(
        <div>
           <div className="card text-white bg-secondary mb-3" style={{"maxWidth":"20rem"}}>

                <div className="card-body">
                    <h4 className="card-title">{todo.title}</h4>
                    <p className="card-text">{todo.description}</p>
                    <p className="card-text">{moment(todo.createdAt).fromNow()}</p>
                    <div style={{display: "flex", justifyContent: "space-between"}} className="actionButtons">
                        <div className="deleteButton"><button type="button" className="btn btn-danger" onClick = {handleDelete}>Delete</button></div>
                        <div className="markTodo"><button type="button" className="btn btn-primary">{todo.isCompleted?"Completed":"Incomplete"}</button></div>
                    </div>
                </div>
            </div>
            <div className = "" style={{ position: "fixed", right: 50,  bottom: 50, zIndex: 1000}}>
                <button type="button" className="btn btn-secondary" data-bs-toggle="modal" data-bs-target="#exampleModal">Add Todo</button>
            </div>
            <AddTodoModal setRefreshList={setRefreshList}/>
            <ToastContainer
                position="top-right"
                autoClose={1500}
                hideProgressBar={false}
                newestOnTop={false}
                closeOnClick
                rtl={false}
                pauseOnFocusLoss
                draggable
                pauseOnHover
            />
        </div>    
    )
}

export default Todo;
